def validate_email(email):
    if not email:
        return False, "Email cannot be empty"
    if "@" not in email:
        return False, "Email must contain @"
    parts = email.split("@")
    if len(parts) != 2:
        return False, "Email must have exactly one @"
    local, domain = parts
    if not local:
        return False, "Email local part cannot be empty"
    if not domain or "." not in domain:
        return False, "Email domain must be valid"
    return True, ""

def validate_username(username):
    if not username:
        return False, "Username cannot be empty"
    if len(username) < 3:
        return False, "Username must be at least 3 chars"
    if len(username) > 20:
        return False, "Username must be at most 20 chars"
    if not username.replace("_", "").isalnum():
        return False, "Username must be alphanumeric or underscore"
    return True, ""

def validate_password(password):
    if not password:
        return False, "Password cannot be empty"
    if len(password) < 8:
        return False, "Password must be at least 8 chars"
    if len(password) > 128:
        return False, "Password must be at most 128 chars"
    has_upper = any(c.isupper() for c in password)
    has_lower = any(c.islower() for c in password)
    has_digit = any(c.isdigit() for c in password)
    if not (has_upper and has_lower and has_digit):
        return False, "Password must have upper, lower, and digit"
    return True, ""
